export function IcoHorizonPanel() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Sky area */}
      <rect x="18" y="18" width="164" height="55" rx="6" fill={palette.mid} opacity="0.15" />
      {/* Horizon line */}
      <line x1="18" y1="73" x2="182" y2="73" stroke={palette.accent} strokeWidth="3" />
      {/* Road trapezoid below horizon */}
      <polygon points="70,73 130,73 162,112 38,112" fill={palette.mid} opacity="0.45" />
      {/* Road lane line */}
      <line x1="100" y1="73" x2="100" y2="112" stroke="rgba(255,255,255,0.18)" strokeWidth="2" strokeDasharray="8 5" />
      {/* Ground frame */}
      <rect x="18" y="73" width="164" height="39" rx="0" fill="none" stroke={palette.mid} strokeWidth="1.5" opacity="0.2" />
    </svg>
  );
}
